"""
Siemens Energy — Gas Turbine Maintenance History API
Lambda handler: /maintenance-history  (GET)

Returns structured maintenance history records for a given equipment asset.
Records are hardcoded to simulate retrieval from a database (DynamoDB / RDS).
In production, replace the HISTORY dictionary with a DynamoDB scan/query.

The records are also contributed to the RAG context window so the AI assistant
can answer questions such as "What are the most common failure patterns for this
turbine?" or "When was the last major overhaul performed?".
"""

import json
import logging

logger = logging.getLogger()
logger.setLevel(logging.INFO)

