def _build_cors_headers(event: dict) -> dict:
    """Return CORS headers. Echoes the request Origin if present."""
    origin = (event.get("headers") or {}).get("origin", "*")
    return {
        "Access-Control-Allow-Origin": origin,
        "Access-Control-Allow-Methods": "GET, OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type, Authorization",
    }


def _error(status: int, message: str, headers: dict) -> dict:
    logger.warning("Returning error %d: %s", status, message)
    return {
        "statusCode": status,
        "headers": {**headers, "Content-Type": "application/json"},
        "body": json.dumps({"error": message}),
    }


def lambda_handler(event: dict, context) -> dict:  # noqa: ANN001
    cors_headers = _build_cors_headers(event)

    # ── Handle CORS preflight ────────────────────────────────────────────────
    method = (event.get("requestContext", {}).get("http", {}) or {}).get("method", "").upper()
    if method == "OPTIONS":
        return {"statusCode": 200, "headers": cors_headers, "body": ""}

    # ── Parse equipment_id query parameter ───────────────────────────────────
    params = event.get("queryStringParameters") or {}
    equipment_id = (params.get("equipment_id") or "").strip()

    if not equipment_id:
        return _error(400, "Missing 'equipment_id' query parameter.", cors_headers)

    logger.info("Maintenance history requested for: %s", equipment_id)

    history = HISTORY.get(equipment_id)
    if history is None:
        return _error(404, f"No maintenance history found for equipment '{equipment_id}'.", cors_headers)

    payload = {
        "equipmentId": equipment_id,
        "count": len(history),
        "records": history,
    }

    return {
        "statusCode": 200,
        "headers": {**cors_headers, "Content-Type": "application/json"},
        "body": json.dumps(payload, ensure_ascii=False),
    }
